import{_ as t,o as e,c as i,R as l}from"./chunks/framework.5IuVB3YY.js";const f=JSON.parse('{"title":"JS数据类型","titleTemplate":"JS基础","description":"","frontmatter":{"title":"JS数据类型","titleTemplate":"JS基础"},"headers":[],"relativePath":"guide/js/data-type.md","filePath":"guide/js/data-type.md"}'),a={name:"guide/js/data-type.md"},r=l('<h1 id="js数据类型" tabindex="-1">JS数据类型 <a class="header-anchor" href="#js数据类型" aria-label="Permalink to &quot;JS数据类型&quot;">​</a></h1><p>JS的数据类型存在以下两个特点：</p><ul><li><strong>动态类型</strong>。JS中的变量与任何特定值类型没有任何关联，任何变量都可以被赋予（和重新赋予）各种类型的值。</li><li><strong>弱类型</strong>。当操作涉及不匹配的类型时，它允许隐式类型转换，而不是抛出类型错误。</li></ul><h2 id="原始值与非原始值" tabindex="-1">原始值与非原始值 <a class="header-anchor" href="#原始值与非原始值" aria-label="Permalink to &quot;原始值与非原始值&quot;">​</a></h2><p>原始值：类型定义了表示在语言最低层面的<strong>不可变值</strong>。我们将这些值称为原始值。</p><blockquote><p>Number、String、Boolean、Null、Undefined、BigInt、Symbol<br><strong>不可变值</strong>表示值不能被更改，但是可以被重新赋值</p></blockquote><p>非原始值：除了原始值之外的值都是原始值。</p><blockquote><p>Object 和 Array、Math...<br> Object 之外的非原始值, Object 都在其原型链上</p></blockquote><h2 id="类型检测" tabindex="-1">类型检测 <a class="header-anchor" href="#类型检测" aria-label="Permalink to &quot;类型检测&quot;">​</a></h2><ol><li>typeof 运算符返回一个字符串，表示操作数的类型。能识别 Number、String、Boolean、Undefined、Function、Object。</li><li>instanceof 运算符用于检测构造函数的 prototype 属性是否出现在某个实例对象的原型链上。只能判断实例对象。</li><li>constructor 是对象原型下一个属性，存放创建该实例对象的构造函数。无法判断 null 和 undefined ，而且 constructor 是可以修改的，会导致检查结果不准确。</li><li>Object.prototype.toString 是对象原型下的方法，返回固定字符串格式为 &quot;[object 类型]&quot;。是最通用最准确的类型检测方法。</li></ol><h2 id="类型转换" tabindex="-1">类型转换 <a class="header-anchor" href="#类型转换" aria-label="Permalink to &quot;类型转换&quot;">​</a></h2><p>由于JS的弱类型特点，意味着经常可以使用与预期类型不同类型的值，并且将为你转换它为正确的类型。</p><h4 id="数字强制转换" tabindex="-1">数字强制转换 <a class="header-anchor" href="#数字强制转换" aria-label="Permalink to &quot;数字强制转换&quot;">​</a></h4><p>数字包含两种数据类型，Number和BigInt，二者的强制转换近乎一致，如果是 Number 强制转化：</p><ul><li>Number 将原样返回</li><li>undefined 转换 NaN</li><li>null 转换为 0</li><li>true 转换为 1; false 转换为0</li><li>字符串如果其值可以解析为数字字面量，则转换为该数字，反之则转换为 NaN <ul><li>Infinity 和 -Infinity 被当作是字面量。它们是全局变量。</li><li>空字符串或仅包含空格的字符串转换为 0。</li></ul></li><li>BigInt 抛出 TypeError，以防止意外的强制隐式转换导致精度损失。</li><li>Symbol 抛出 TypeError。</li><li>对象首先通过按顺序调用它们的 [@@toPrimitive](number)、valueOf() 和 toString() 方法将其转换为原始值。然后将得到的原始值转换为数字。</li></ul><p>如果是 BigInt 强制转换，则将 BigInt 原样返回，Number 抛出 TypeError。<br> 如果是数字强制转换，则将 BigInt 和 Number 都原样返回</p><h4 id="字符串强制转换" tabindex="-1">字符串强制转换 <a class="header-anchor" href="#字符串强制转换" aria-label="Permalink to &quot;字符串强制转换&quot;">​</a></h4><ul><li>字符串按原样返回。</li><li>undefined 转换成 &quot;undefined&quot;。</li><li>null 转换成 &quot;null&quot;。</li><li>true 转换成 &quot;true&quot;；false 转换成 &quot;false&quot;。</li><li>使用与 toString(10) 相同的算法转换数字。</li><li>使用与 toString(10) 相同的算法转换 BigInt。</li><li>Symbol 抛出 TypeError。</li><li>对象首先通过依次调用其 [@@toPrimitive](string)、toString() 和 valueOf() 方法将其转换为原始值。然后将生成的原始值转换为一个字符串。</li></ul><h4 id="布尔值强制转换" tabindex="-1">布尔值强制转换 <a class="header-anchor" href="#布尔值强制转换" aria-label="Permalink to &quot;布尔值强制转换&quot;">​</a></h4><ul><li>+0、-0、NaN 转换为 false</li><li>&#39;&#39; 转换为 false</li><li>null 转换为 false</li><li>undefined 转换为 false</li><li>其他均转换为 true</li></ul><h4 id="原始值强制转换" tabindex="-1">原始值强制转换 <a class="header-anchor" href="#原始值强制转换" aria-label="Permalink to &quot;原始值强制转换&quot;">​</a></h4><p>如果值已经是原始值，则不会进行原始值强制转换操作，而是根据转换需要执行以上的转换操作<br> 如果是对象将依次调用它的 [@@toPrimitive](default)、valueOf() 和 toString() 方法，将其转换为原始值。</p><p><strong>特殊说明</strong>：[@@toPrimitive] 不是一定存在，但是如果存在，则必然会首先调用并将原始值返回，如果返回对象，会导致 TypeError</p>',23),o=[r];function n(u,s,d,c,h,p){return e(),i("div",null,o)}const m=t(a,[["render",n]]);export{f as __pageData,m as default};
